sys_transform_script.script:
(function runTransformScript(source, map, log, target /*undefined onStart*/ ) {
    // Populate a location Reference for all rows using
    // the DT API

    // first get the decision table
    var gr_decision = new GlideRecord("sys_decision");
    gr_decision.addQuery("name", "Vendor Location Lookup");
    gr_decision.setLimit(1);
    gr_decision.query();
    gr_decision.next(); // check omitted for readability
    var decision = gr_decision.getValue("sys_id");

    // Use the DT to populate a Location reference.

    // Important! Calling the DT for each import set row, 
    // as shown here, is inefficient. Instead, do one of:
    // - get the whole DT via the API and pull out all the
    //   conditions and answers, and put them in a map, OR
    // - do like shown here but cache each response
	var dt = new sn_dt.DecisionTableAPI();
    var gr_is_row = new GlideRecord("x_42999_decision_0_hardware_location");
    gr_is_row.addQuery("sys_import_set", import_set.sys_id);
    gr_is_row.query();
    while (gr_is_row.hasNext()) {
		gr_is_row.next();
        var inputs = {};
        inputs['u_location'] = gr_is_row.getValue("u_location");
        var response = dt.getDecision(decision, inputs);
        if (response) {
            var result_elements = response.result_elements;
            var u_ref = result_elements.u_location.getValue();
            if (u_ref) {
                gr_is_row.setValue("u_location_ref", u_ref);
                gr_is_row.update();
            }
        }
    }

})(source, map, log, target);
